"python3 << 'EOF'
import os
import re

EPISODES_DIR = "episodes"
files = sorted([f for f in os.listdir(EPISODES_DIR) if f.startswith("第") and f.endswith(".md")])

issues = {}

for fname in files:
    fpath = os.path.join(EPISODES_DIR, fname)
    with open(fpath, 'r', encoding='utf-8') as f:
        content = f.read()
        lines = content.split('\n')

    file_issues = []

    for i, line in enumerate(lines, 1):
        # Check for "即将发布" - should be updated now
        if '即将发布' in line:
            file_issues.append(f"  L{i}: 含'即将发布' -> {line.strip()[:60]}")
        # Check for repeated words like 拥抱拥抱
        if re.search(r'(\w{2})\1', line):
            matches = re.findall(r'(\w{2})\1', line)
            if matches:
                file_issues.append(f"  L{i}: 可能重复词汇 {matches} -> {line.strip()[:60]}")
        # Check for TODO/placeholder
        if re.search(r'TODO|PLACEHOLDER|待补充|待完善', line, re.IGNORECASE):
            file_issues.append(f"  L{i}: 待完善内容 -> {line.strip()[:60]}")
        # Check for 数据来源 remaining
        if re.match(r'^\*?\s*数据来源', line):
            file_issues.append(f"  L{i}: 数据来源残留 -> {line.strip()[:60]}")

    if file_issues:
        issues[fname] = file_issues

if issues:
    for fname, iss in issues.items():
        print(f"\n=== {fname} ===")
        for i in iss:
            print(i)
else:
    print("✅ 全部文章检查通过，无明显异常")
EOF"
